class ActionCommandReturn
    attr_reader :return_value
    attr_reader :return_value_type
    attr_reader :closure_argument_value

    def initialize(return_value: nil, return_value_type: nil, closure_argument_value: nil)
      @return_value = return_value
      @closure_argument_value = closure_argument_value
      @return_value_type = return_value_type
    end
  end

class DuplicateNamesError < GraphQL::Error
      attr_reader :duplicated_name
      def initialize(duplicated_name:, duplicated_definition_1:, duplicated_definition_2:)
        @duplicated_name = duplicated_name
        super(
          "Found two visible definitions for `#{duplicated_name}`: #{duplicated_definition_1}, #{duplicated_definition_2}"
        )
      end
    end

if !directive_defn.locations.include?(required_location)
